1	/// Setup steps in first-run wizard order.
2	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
3	pub enum SetupStep {
4	    CreateConfig,
5	    InstallModel,
6	    SetupUinput,
7	    ConfigurePtt,
8	}
9	
10	/// Pure-logic state for the first-run setup wizard.
11	pub struct FirstRunState {
12	    config_exists: bool,
13	    model_installed: bool,
14	    uinput_accessible: bool,
15	    ptt_configured: bool,
16	}
17	
18	impl FirstRunState {
19	    /// Construct from environment probe results.
20	    pub fn from_checks(
21	        config_exists: bool,
22	        model_installed: bool,
23	        uinput_accessible: bool,
24	        ptt_configured: bool,
25	    ) -> Self {
26	        Self {
27	            config_exists,
28	            model_installed,
29	            uinput_accessible,
30	            ptt_configured,
31	        }
32	    }
33	
34	    /// True when every setup prerequisite is satisfied.
35	    pub fn is_setup_complete(&self) -> bool {
36	        self.config_exists
37	            && self.model_installed
38	            && self.uinput_accessible
39	            && self.ptt_configured
40	    }
41	
42	    /// Ordered list of steps that are not yet done (wizard order).
43	    pub fn steps_remaining(&self) -> Vec<SetupStep> {
44	        let mut steps = Vec::new();
45	        if !self.config_exists {
46	            steps.push(SetupStep::CreateConfig);
47	        }
48	        if !self.model_installed {
49	            steps.push(SetupStep::InstallModel);
50	        }
51	        if !self.uinput_accessible {
52	            steps.push(SetupStep::SetupUinput);
53	        }
54	        if !self.ptt_configured {
55	            steps.push(SetupStep::ConfigurePtt);
56	        }
57	        steps
58	    }
59	
60	    /// First step the user still needs to complete, or None if done.
61	    pub fn first_incomplete_step(&self) -> Option<SetupStep> {
62	        self.steps_remaining().into_iter().next()
63	    }
64	}
